#ifndef MIX_Kernels_CL_H
#define MIX_Kernels_CL_H

#ifdef ENABLE_DP
#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#endif

#ifdef ENABLE_HP
#pragma OPENCL EXTENSION cl_khr_fp16 : enable
#endif

#ifdef class_T
typedef class_T T;
#else
typedef float T;
#endif

#ifdef BLOCK_STRIDED
#define STRIDE_MODE 1
#else
#define STRIDE_MODE 0
#endif

#ifndef ELEMENTS_PER_THREAD
#define ELEMENTS_PER_THREAD 8
#endif

#ifndef FUSION_DEGREE
#define FUSION_DEGREE 4
#endif

#ifndef COMPUTE_ITERATIONS
#define COMPUTE_ITERATIONS 1
#endif

#ifndef blockdim
#define blockdim 256
#endif

inline T conv_int(int i) {
#ifdef ENABLE_HP
    if (sizeof(T) == 4 && sizeof(half2) == 4) { // Approximation for half2 context if needed, but usually T is explicit
        // This template specialization logic is hard to map directly. 
        // We rely on the build parameter -Dclass_T=half2 to set T to half2
        return __float2half((float)i); // Fallback, actual half2 handling below
    }
#endif
    return (T)i;
}

#ifdef ENABLE_HP
inline half2 conv_int_half2(int i) {
    return __float2half2((float)i);
}
#endif

inline T mad_impl(T a, T b, T c) {
    return a * b + c;
}

#ifdef ENABLE_HP
inline half2 mad_impl_half2(half2 a, half2 b, half2 c) {
    return __hfma(a, b, c);
}
#endif

inline int equal_impl(T a, T b) {
    return (a == b) ? 1 : 0;
}

#ifdef ENABLE_HP
inline int equal_impl_half2(half2 a, half2 b) {
    return (a.x == b.x && a.y == b.y) ? 1 : 0;
}
#endif

__kernel void benchmark_func(T seed, __global T *g_data) {
    const unsigned int blockSize = blockdim;
    const int stride = blockSize;

    // Calculate index based on striding mode
    int idx;
    if (STRIDE_MODE) {
        // Block strided: blockIdx.x * blockSize * granularity + threadIdx.x
        // In OpenCL: get_group_id(0) * blockSize * ELEMENTS_PER_THREAD + get_local_id(0)
        idx = get_group_id(0) * blockSize * ELEMENTS_PER_THREAD + get_local_id(0);
    } else {
        // NDRange linear: global_id
        idx = get_global_id(0);
    }

    const int big_stride = get_num_groups(0) * blockSize * ELEMENTS_PER_THREAD;

    T tmps[ELEMENTS_PER_THREAD];

    // Load data
    for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
        // Initial load for k=0, then we loop fusion_degree
        // The CUDA code loads: g_data[idx + j*stride + k*big_stride]
        // Since we process k in the outer loop, we load inside the k loop
        // But to match the structure exactly:
        // CUDA: tmps[j] = g_data[idx+j*stride+k*big_stride];
        // We must do this inside the k loop.
    }

    for (int k = 0; k < FUSION_DEGREE; k++) {
        // Load
        for (int j = 0; j < ELEMENTS_PER_THREAD; j++) {
            tmps[j] = g_data[idx + j * stride + k * big_stride];

            // Compute iterations
            // Unroll hint: TemperateUnroll ? 4 : 128. 
            // In OpenCL, we can't dynamically choose unroll based on boolean template easily without macros.
            // We assume standard unroll or let compiler decide.
            for (int i = 0; i < COMPUTE_ITERATIONS; i++) {
#ifdef ENABLE_HP
                if (sizeof(T) == sizeof(half2)) {
                    tmps[j] = mad_impl_half2(tmps[j], tmps[j], seed);
                } else {
                    tmps[j] = mad_impl(tmps[j], tmps[j], seed);
                }
#else
                tmps[j] = mad_impl(tmps[j], tmps[j], seed);
#endif
            }
        }

        T sum = conv_int(0);
#ifdef ENABLE_HP
        if (sizeof(T) == sizeof(half2)) {
            sum = conv_int_half2(0);
        }
#endif

        // Reduction
        for (int j = 0; j < ELEMENTS_PER_THREAD; j += 2) {
#ifdef ENABLE_HP
            if (sizeof(T) == sizeof(half2)) {
                sum = mad_impl_half2(tmps[j], tmps[j+1], sum);
            } else {
                sum = mad_impl(tmps[j], tmps[j+1], sum);
            }
#else
            sum = mad_impl(tmps[j], tmps[j+1], sum);
#endif
        }

        // Check and store
        int is_neg_one = 0;
#ifdef ENABLE_HP
        if (sizeof(T) == sizeof(half2)) {
            half2 neg_one = __float2half2(-1.0f);
            if (equal_impl_half2(sum, neg_one)) is_neg_one = 1;
        } else {
            if (equal_impl(sum, (T)-1)) is_neg_one = 1;
        }
#else
        if (equal_impl(sum, (T)-1)) is_neg_one = 1;
#endif

        if (is_neg_one) {
            g_data[idx + k * big_stride] = sum;
        }
    }
}

#endif
